/**
 * Automatic Dynamic SEO Engine.
 *
 * Every route gets a base title/description; keywords are auto-generated by
 * extracting meaningful terms from that copy (no manual keyword list to
 * maintain per page). New routes automatically fall back to a sensible
 * default so nothing ever ships without meta tags.
 */

interface RouteMeta {
  title: string;
  description: string;
}

const SITE_NAME = "Global AI Hub";

const STOPWORDS = new Set([
  "the", "and", "for", "with", "your", "you", "our", "are", "from", "into",
  "that", "this", "all", "a", "an", "to", "of", "in", "on", "is", "it",
  "by", "or", "as", "be", "at", "we", "us",
]);

export function generateKeywords(title: string, description: string, extra: string[] = []): string[] {
  const text = `${title} ${description} ${extra.join(" ")}`.toLowerCase();
  const words = text
    .split(/[^a-z0-9+]+/)
    .filter((w) => w.length > 2 && !STOPWORDS.has(w));
  return Array.from(new Set([...extra.map((e) => e.toLowerCase()), ...words])).slice(0, 15);
}

