const DEFAULT_META: RouteMeta = {
  title: SITE_NAME,
  description: "Discover, build, and scale with the entire AI universe — tools, news, marketplace, and more.",
};

export function getRouteMeta(pathname: string): { title: string; description: string; keywords: string[] } {
  const base = ROUTE_META[pathname] ?? DEFAULT_META;
  const keywords = generateKeywords(base.title, base.description, ["AI tools", "artificial intelligence", "global ai hub"]);
  return { ...base, keywords };
}
